import{_ as o,o as e,c as l,ai as n}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Strict Config Validation","description":"","frontmatter":{"summary":"Strict config validation + doctor-only migrations","read_when":["Designing or implementing config validation behavior","Working on config migrations or doctor workflows","Handling plugin config schemas or plugin load gating"],"title":"Strict Config Validation"},"headers":[],"relativePath":"refactor/strict-config.md","filePath":"refactor/strict-config.md","lastUpdated":null}'),a={name:"refactor/strict-config.md"};function t(r,i,s,c,d,g){return e(),l("div",null,[...i[0]||(i[0]=[n('<h1 id="strict-config-validation-doctor-only-migrations" tabindex="-1"><a class="header-anchor" href="#strict-config-validation-doctor-only-migrations">#</a> Strict config validation (doctor-only migrations)</h1><h2 id="goals" tabindex="-1"><a class="header-anchor" href="#goals">#</a> Goals</h2><ul><li><strong>Reject unknown config keys everywhere</strong> (root + nested).</li><li><strong>Reject plugin config without a schema</strong>; don’t load that plugin.</li><li><strong>Remove legacy auto-migration on load</strong>; migrations run via doctor only.</li><li><strong>Auto-run doctor (dry-run) on startup</strong>; if invalid, block non-diagnostic commands.</li></ul><h2 id="non-goals" tabindex="-1"><a class="header-anchor" href="#non-goals">#</a> Non-goals</h2><ul><li>Backward compatibility on load (legacy keys do not auto-migrate).</li><li>Silent drops of unrecognized keys.</li></ul><h2 id="strict-validation-rules" tabindex="-1"><a class="header-anchor" href="#strict-validation-rules">#</a> Strict validation rules</h2><ul><li>Config must match the schema exactly at every level.</li><li>Unknown keys are validation errors (no passthrough at root or nested).</li><li><code>plugins.entries.&lt;id&gt;.config</code> must be validated by the plugin’s schema. <ul><li>If a plugin lacks a schema, <strong>reject plugin load</strong> and surface a clear error.</li></ul></li><li>Unknown <code>channels.&lt;id&gt;</code> keys are errors unless a plugin manifest declares the channel id.</li><li>Plugin manifests (<code>opensoul.plugin.json</code>) are required for all plugins.</li></ul><h2 id="plugin-schema-enforcement" tabindex="-1"><a class="header-anchor" href="#plugin-schema-enforcement">#</a> Plugin schema enforcement</h2><ul><li>Each plugin provides a strict JSON Schema for its config (inline in the manifest).</li><li>Plugin load flow: <ol><li>Resolve plugin manifest + schema (<code>opensoul.plugin.json</code>).</li><li>Validate config against the schema.</li><li>If missing schema or invalid config: block plugin load, record error.</li></ol></li><li>Error message includes: <ul><li>Plugin id</li><li>Reason (missing schema / invalid config)</li><li>Path(s) that failed validation</li></ul></li><li>Disabled plugins keep their config, but Doctor + logs surface a warning.</li></ul><h2 id="doctor-flow" tabindex="-1"><a class="header-anchor" href="#doctor-flow">#</a> Doctor flow</h2><ul><li>Doctor runs <strong>every time</strong> config is loaded (dry-run by default).</li><li>If config invalid: <ul><li>Print a summary + actionable errors.</li><li>Instruct: <code>opensoul doctor --fix</code>.</li></ul></li><li><code>opensoul doctor --fix</code>: <ul><li>Applies migrations.</li><li>Removes unknown keys.</li><li>Writes updated config.</li></ul></li></ul><h2 id="command-gating-when-config-is-invalid" tabindex="-1"><a class="header-anchor" href="#command-gating-when-config-is-invalid">#</a> Command gating (when config is invalid)</h2><p>Allowed (diagnostic-only):</p><ul><li><code>opensoul doctor</code></li><li><code>opensoul logs</code></li><li><code>opensoul health</code></li><li><code>opensoul help</code></li><li><code>opensoul status</code></li><li><code>opensoul gateway status</code></li></ul><p>Everything else must hard-fail with: “Config invalid. Run <code>opensoul doctor --fix</code>.”</p><h2 id="error-ux-format" tabindex="-1"><a class="header-anchor" href="#error-ux-format">#</a> Error UX format</h2><ul><li>Single summary header.</li><li>Grouped sections: <ul><li>Unknown keys (full paths)</li><li>Legacy keys / migrations needed</li><li>Plugin load failures (plugin id + reason + path)</li></ul></li></ul><h2 id="implementation-touchpoints" tabindex="-1"><a class="header-anchor" href="#implementation-touchpoints">#</a> Implementation touchpoints</h2><ul><li><code>src/config/zod-schema.ts</code>: remove root passthrough; strict objects everywhere.</li><li><code>src/config/zod-schema.providers.ts</code>: ensure strict channel schemas.</li><li><code>src/config/validation.ts</code>: fail on unknown keys; do not apply legacy migrations.</li><li><code>src/config/io.ts</code>: remove legacy auto-migrations; always run doctor dry-run.</li><li><code>src/config/legacy*.ts</code>: move usage to doctor only.</li><li><code>src/plugins/*</code>: add schema registry + gating.</li><li>CLI command gating in <code>src/cli</code>.</li></ul><h2 id="tests" tabindex="-1"><a class="header-anchor" href="#tests">#</a> Tests</h2><ul><li>Unknown key rejection (root + nested).</li><li>Plugin missing schema → plugin load blocked with clear error.</li><li>Invalid config → gateway startup blocked except diagnostic commands.</li><li>Doctor dry-run auto; <code>doctor --fix</code> writes corrected config.</li></ul>',21)])])}const f=o(a,[["render",t]]);export{h as __pageData,f as default};
